import React, { useState, useEffect } from 'react';
import './App.css';

function App() {
  const [file, setFile] = useState(null);
  const [extractedText, setExtractedText] = useState('');
  const [processedText, setProcessedText] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  // Load Puter script
  useEffect(() => {
    const script = document.createElement('script');
    script.src = 'https://js.puter.com/v2/';
    script.async = true;
    document.body.appendChild(script);
  }, []);

  const handleFileChange = (e) => {
    const selectedFile = e.target.files[0];
    if (selectedFile) {
      setFile(selectedFile);
      setError('');
    }
  };

  const handleUpload = async (e) => {
    e.preventDefault();
    
    if (!file) {
      setError('Please select a file first');
      return;
    }

    setLoading(true);
    setError('');
    setExtractedText('');
    setProcessedText('');

    try {
      // Step 1: Upload file to backend
      const formData = new FormData();
      formData.append('file', file);

      const uploadResponse = await fetch('http://localhost:8000/ocr', {
        method: 'POST',
        body: formData,
      });

      if (!uploadResponse.ok) {
        throw new Error('Failed to upload file');
      }

      const uploadData = await uploadResponse.json();
      
      if (uploadData.error) {
        throw new Error(uploadData.error);
      }

      const dataUrl = uploadData.data_url;

      // Step 2: Use Puter's client-side img2txt to extract text
      if (!window.puter) {
        throw new Error('Puter library not loaded. Please check your internet connection.');
      }

      let rawOcrText = '';
      
      try {
        rawOcrText = await window.puter.ai.img2txt(dataUrl);
      } catch (puterError) {
        throw new Error(`Puter OCR failed: ${puterError.message}`);
      }

      // Parse OCR output: extract paragraph format (text with spaces)
      // Puter returns: "paragraph text" + "\n\n" + "word\nword\nword..."
      const parts = rawOcrText.split('\n\n');
      const extractedTextContent = parts[0].trim(); // Get only the paragraph part

      setExtractedText(extractedTextContent);

      // Step 3: Send extracted text to backend for preprocessing
      const preprocessResponse = await fetch('http://localhost:8000/preprocess', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ text: extractedTextContent }),
      });

      if (!preprocessResponse.ok) {
        throw new Error('Failed to preprocess text');
      }

      const preprocessData = await preprocessResponse.json();
      setProcessedText(preprocessData.processed_text || '');

    } catch (err) {
      setError(`Error: ${err.message}`);
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="container">
      <header className="header">
        <h1>AI-Assisted Exam Evaluator</h1>
        <p>Upload exam answer sheets for OCR and preprocessing</p>
      </header>

      <main className="main">
        <section className="upload-section">
          <form onSubmit={handleUpload}>
            <div className="file-input-wrapper">
              <label htmlFor="file-input" className="file-label">
                Choose Image or PDF
              </label>
              <input
                id="file-input"
                type="file"
                onChange={handleFileChange}
                accept="image/*,.pdf"
                disabled={loading}
              />
              {file && <p className="file-name">Selected: {file.name}</p>}
            </div>

            <button 
              type="submit" 
              className="upload-btn"
              disabled={loading || !file}
            >
              {loading ? 'Processing...' : 'Upload & Process'}
            </button>
          </form>

          {error && <div className="error-message">{error}</div>}
        </section>

        <section className="results-section">
          <div className="text-area-wrapper">
            <label htmlFor="extracted">Extracted Text (Puter OCR)</label>
            <textarea
              id="extracted"
              value={extractedText}
              readOnly
              placeholder="OCR extracted text will appear here..."
            />
          </div>

          <div className="text-area-wrapper">
            <label htmlFor="processed">Preprocessed Text</label>
            <textarea
              id="processed"
              value={processedText}
              readOnly
              placeholder="Cleaned and preprocessed text will appear here..."
            />
          </div>
        </section>
      </main>

      <footer className="footer">
        <p>Phase: Input → Upload → Puter OCR → Text Preprocessing | Ready for subjective evaluation</p>
      </footer>
    </div>
  );
}

export default App;
